const csvData = $json.data || '';
const lines = csvData.trim().split('\n');

if (lines.length < 2) {
  return [{
    status: 'ERROR',
    data_quality_issues: ['No data received'],
    risk_summary: { high_risk: 0, medium_risk: 0, low_risk: 0, total_patients: 0 },
    urgent_patients: [],
    urgent_line: 'No data available.',
    urgent_count: 0
  }];
}

const headers = lines[0].split(',').map(h => h.trim());

const rows = [];
for (let i = 1; i < lines.length; i++) {
  const vals = lines[i].split(',');
  const row = {};
  headers.forEach((h, idx) => {
    row[h] = vals[idx] !== undefined ? vals[idx].trim() : '';
  });
  rows.push(row);
}

let missingPatientIds = 0;
let missingReadmission = 0;
let sentinelBills = 0;

rows.forEach(r => {
  if (!r.patient_id) missingPatientIds++;
  if (!r.readmission_30d) missingReadmission++;
  if (r.total_bill_usd === '-9999') sentinelBills++;
});

const totalIssues = missingPatientIds + missingReadmission + sentinelBills;
const status = totalIssues > 0 ? 'BLOCKED' : 'OK';

let high = 0, medium = 0, low = 0;
rows.forEach(r => {
  const readmit = parseInt(r.readmission_30d);
  if (readmit === 1) high++;
  else low++;
});
medium = rows.length - high - low;

const urgent = rows.filter(r => parseInt(r.readmission_30d) === 1);

const urgentLines = urgent.map((r, i) =>
  `${i+1}. Patient ${r.patient_id || 'UNKNOWN'} | Age: ${r.age} | Dept: ${r.department} | Bill: $${r.total_bill_usd}`
);

const output = {
  status: status,
  data_quality_issues: [
    `Missing patient_ids: ${missingPatientIds}`,
    `Missing readmission_30d: ${missingReadmission}`,
    `Sentinel -9999 bills: ${sentinelBills}`
  ],
  risk_summary: {
    high_risk: high,
    medium_risk: medium,
    low_risk: low,
    total_patients: rows.length
  },
  urgent_patients: urgent,
  urgent_line: urgent.length > 0
    ? 'URGENT patients requiring immediate follow-up:\n' + urgentLines.join('\n')
    : 'No URGENT patients today.',
  urgent_count: urgent.length
};

return [output];

